-- ============================================================
-- DevBridge: 다양화된 시드 (파트너 200 + 클라이언트 100)
-- 생성: scripts/generate_diverse_seed.py
-- 보호: hyleeyou(id=3043), client_hylee(id=3044), 그들의 프로젝트(1165~1170)
--       및 관련 row 는 절대 삭제하지 않습니다.
-- ============================================================
SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS=1;

-- ============================================================
-- PART A. 정리 (사용자 확인 후 실행)
-- 주의: 아래 DELETE 는 hyleeyou/client_hylee 데이터를 제외한 모든 시드를 제거합니다.
-- ============================================================
START TRANSACTION;

-- 1) 프로젝트의 자식 row 들 (hylee 프로젝트 제외)
DELETE FROM project_application WHERE project_id NOT IN (1165,1166,1167,1168,1169,1170);
DELETE FROM project_attachments WHERE project_id NOT IN (1165,1166,1167,1168,1169,1170);
DELETE FROM project_escrows WHERE project_id NOT IN (1165,1166,1167,1168,1169,1170);
DELETE FROM project_meetings WHERE project_id NOT IN (1165,1166,1167,1168,1169,1170);
DELETE FROM project_milestones WHERE project_id NOT IN (1165,1166,1167,1168,1169,1170);
DELETE FROM project_modules WHERE project_id NOT IN (1165,1166,1167,1168,1169,1170);
DELETE FROM project_skill_mapping WHERE project_id NOT IN (1165,1166,1167,1168,1169,1170);
DELETE FROM project_tags WHERE project_id NOT IN (1165,1166,1167,1168,1169,1170);

-- 2) 리뷰 (hylee 와 무관한 것만)
DELETE FROM partner_review WHERE (project_id IS NULL OR project_id NOT IN (1165,1166,1167,1168,1169,1170)) AND reviewer_user_id NOT IN (3043,3044) AND partner_profile_id NOT IN (SELECT id FROM partner_profile WHERE user_id IN (3043,3044));
DELETE FROM client_review  WHERE (project_id IS NULL OR project_id NOT IN (1165,1166,1167,1168,1169,1170)) AND reviewer_user_id NOT IN (3043,3044) AND client_profile_id  NOT IN (SELECT id FROM client_profile  WHERE user_id IN (3043,3044));

-- 3) 관심/장바구니류 (관심 데이터는 모두 비움)
DELETE FROM user_interest_partners;
DELETE FROM user_interest_projects;

-- 4) 사용자 부가 정보 (hylee 제외)
DELETE FROM user_award WHERE user_id NOT IN (3043,3044);
DELETE FROM user_career WHERE user_id NOT IN (3043,3044);
DELETE FROM user_certification WHERE user_id NOT IN (3043,3044);
DELETE FROM user_education WHERE user_id NOT IN (3043,3044);
DELETE FROM user_profile_detail WHERE user_id NOT IN (3043,3044);
DELETE FROM user_skill_detail WHERE user_id NOT IN (3043,3044);
DELETE FROM payment_methods WHERE user_id NOT IN (3043,3044);
DELETE FROM notification WHERE user_id NOT IN (3043,3044);

-- 5) 포트폴리오 (hylee 본인 제외)
DELETE FROM partner_portfolios WHERE user_id NOT IN (3043,3044);
-- 5-1) hylee 포트폴리오의 dangling FK 는 NULL 로 (row 자체는 보존)
UPDATE partner_portfolios SET source_project_id=NULL WHERE user_id IN (3043,3044) AND (source_project_id IS NULL OR source_project_id NOT IN (1165,1166,1167,1168,1169,1170));

-- 6) 채팅방 (hylee 가 참여하지 않는 모든 채팅방)
DELETE FROM chat_room WHERE user1_id NOT IN (3043,3044) AND user2_id NOT IN (3043,3044);

-- 7) 프로필 자식 → 프로필 (hylee 제외)
DELETE FROM partner_skill          WHERE partner_profile_id NOT IN (SELECT id FROM partner_profile WHERE user_id IN (3043,3044));
DELETE FROM partner_profile_stats  WHERE partner_profile_id NOT IN (SELECT id FROM partner_profile WHERE user_id IN (3043,3044));
DELETE FROM client_preferred_skill WHERE client_profile_id  NOT IN (SELECT id FROM client_profile  WHERE user_id IN (3043,3044));
DELETE FROM client_profile_stats   WHERE client_profile_id  NOT IN (SELECT id FROM client_profile  WHERE user_id IN (3043,3044));

-- 8) 프로젝트 (hylee 프로젝트 제외)
DELETE FROM projects WHERE id NOT IN (1165,1166,1167,1168,1169,1170);

-- 9) 프로필 (hylee 제외)
DELETE FROM partner_profile WHERE user_id NOT IN (3043,3044);
DELETE FROM client_profile  WHERE user_id NOT IN (3043,3044);

-- 10) 사용자 (hylee 제외)
DELETE FROM users WHERE id NOT IN (3043,3044);

COMMIT;

